### Step 10: Create Server API Endpoints

Create `SiteInspector/Endpoints/SyncEndpoints.cs`:
```csharp
using System.Text.Json;

namespace SiteInspector.Endpoints;

public static class SyncEndpoints
{
    private static readonly List<JsonElement> _syncedData = new();
    private static readonly Dictionary<string, JsonElement> _sites = new();
    private static readonly Dictionary<string, JsonElement> _inspections = new();

    public static void MapSyncEndpoints(this WebApplication app)
    {
        app.MapPost("/api/sync", (JsonElement[] items) =>
        {
            foreach (var item in items)
            {
                _syncedData.Add(item);

                if (item.TryGetProperty("entityType", out var entityType) &&
                    item.TryGetProperty("entityId", out var entityId) &&
                    item.TryGetProperty("payload", out var payload))
                {
                    var type = entityType.GetString();
                    var id = entityId.GetString();
                    if (type == "Site" && id != null)
                    {
                        _sites[id] = payload;
                    }
                    else if (type == "Inspection" && id != null)
                    {
                        _inspections[id] = payload;
                    }
                }
            }
            return Results.Ok(new { processed = items.Length });
        });

        app.MapGet("/api/sites", () =>
        {
            return Results.Ok(_sites.Values);
        });

        app.MapGet("/api/inspections/{siteId}", (string siteId) =>
        {
            var results = _inspections.Values.Where(i =>
            {
                if (i.TryGetProperty("siteId", out var sid))
                    return sid.GetString() == siteId;
                return false;
            });
            return Results.Ok(results);
        });
    }
}
```

