const DB_NAME = 'SiteInspectorDb';
const DB_VERSION = 1;
let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const inspStore = database.createObjectStore('inspections', { keyPath: 'id' });
                inspStore.createIndex('siteId', 'siteId', { unique: false });
            }
            if (!database.objectStoreNames.contains('checklistItems')) {
                const clStore = database.createObjectStore('checklistItems', { keyPath: 'id' });
                clStore.createIndex('inspectionId', 'inspectionId', { unique: false });
            }
            if (!database.objectStoreNames.contains('photos')) {
                const photoStore = database.createObjectStore('photos', { keyPath: 'id' });
                photoStore.createIndex('inspectionId', 'inspectionId', { unique: false });
            }
            if (!database.objectStoreNames.contains('syncQueue')) {
                const syncStore = database.createObjectStore('syncQueue', { keyPath: 'id' });
                syncStore.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDb = {
    initialize: async function () {
        await openDb();
        return true;
    },

    putItem: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.put(item);
            request.onsuccess = () => resolve(true);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function (storeName, indexName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const index = store.index(indexName);
            const request = index.getAll(key);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.delete(id);
            request.onsuccess = () => resolve(true);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getPendingSyncItems: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('syncQueue', 'readonly');
            const store = tx.objectStore('syncQueue');
            const index = store.index('isSynced');
            const request = index.getAll(false);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    markAsSynced: async function (id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('syncQueue', 'readwrite');
            const store = tx.objectStore('syncQueue');
            const getReq = store.get(id);
            getReq.onsuccess = () => {
                const item = getReq.result;
                if (item) {
                    item.isSynced = true;
                    const putReq = store.put(item);
                    putReq.onsuccess = () => resolve(true);
                    putReq.onerror = (e) => reject(e.target.error);
                } else {
                    resolve(false);
                }
            };
            getReq.onerror = (e) => reject(e.target.error);
        });
    },

    isOnline: function () {
        return navigator.onLine;
    }
};

using Microsoft.JSInterop;
using System.Text.Json;

namespace SiteInspector.Client.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _jsRuntime;
    private bool _initialized;

    public IndexedDbService(IJSRuntime jsRuntime)
    {
        _jsRuntime = jsRuntime;
    }

    public async Task InitializeAsync()
    {
        if (_initialized) return;
        await _jsRuntime.InvokeVoidAsync("indexedDb.initialize");
        _initialized = true;
    }

    public async Task PutItemAsync<T>(string storeName, T item)
    {
        await InitializeAsync();
        var json = JsonSerializer.Serialize(item, new JsonSerializerOptions { PropertyNamingPolicy = JsonNamingPolicy.CamelCase });
        var element = JsonSerializer.Deserialize<object>(json);
        await _jsRuntime.InvokeVoidAsync("indexedDb.putItem", storeName, element);
    }

    public async Task<T?> GetItemAsync<T>(string storeName, string id)
    {
        await InitializeAsync();
        var result = await _jsRuntime.InvokeAsync<JsonElement?>("indexedDb.getItem", storeName, id);
        if (result == null || result.Value.ValueKind == JsonValueKind.Undefined || result.Value.ValueKind == JsonValueKind.Null)
            return default;
        return JsonSerializer.Deserialize<T>(result.Value.GetRawText(), new JsonSerializerOptions { PropertyNameCaseInsensitive = true });
    }

    public async Task<List<T>> GetAllItemsAsync<T>(string storeName)
    {
        await InitializeAsync();
        var result = await _jsRuntime.InvokeAsync<JsonElement>("indexedDb.getAllItems", storeName);
        if (result.ValueKind == JsonValueKind.Null || result.ValueKind == JsonValueKind.Undefined)
            return new List<T>();
        return JsonSerializer.Deserialize<List<T>>(result.GetRawText(), new JsonSerializerOptions { PropertyNameCaseInsensitive = true }) ?? new List<T>();
    }

    public async Task<List<T>> GetItemsByIndexAsync<T>(string storeName, string indexName, string key)
    {
        await InitializeAsync();
        var result = await _jsRuntime.InvokeAsync<JsonElement>("indexedDb.getItemsByIndex", storeName, indexName, key);
        if (result.ValueKind == JsonValueKind.Null || result.ValueKind == JsonValueKind.Undefined)
            return new List<T>();
        return JsonSerializer.Deserialize<List<T>>(result.GetRawText(), new JsonSerializerOptions { PropertyNameCaseInsensitive = true }) ?? new List<T>();
    }

    public async Task DeleteItemAsync(string storeName, string id)
    {
        await InitializeAsync();
        await _jsRuntime.InvokeVoidAsync("indexedDb.deleteItem", storeName, id);
    }

    public async Task<List<T>> GetPendingSyncItemsAsync<T>()
    {
        await InitializeAsync();
        var result = await _jsRuntime.InvokeAsync<JsonElement>("indexedDb.getPendingSyncItems");
        if (result.ValueKind == JsonValueKind.Null || result.ValueKind == JsonValueKind.Undefined)
            return new List<T>();
        return JsonSerializer.Deserialize<List<T>>(result.GetRawText(), new JsonSerializerOptions { PropertyNameCaseInsensitive = true }) ?? new List<T>();
    }

    public async Task MarkAsSyncedAsync(string id)
    {
        await InitializeAsync();
        await _jsRuntime.InvokeVoidAsync("indexedDb.markAsSynced", id);
    }

    public async Task<bool> IsOnlineAsync()
    {
        return await _jsRuntime.InvokeAsync<bool>("indexedDb.isOnline");
    }
}

using SiteInspector.Client.Models;
using System.Text.Json;

namespace SiteInspector.Client.Services;

public class InspectionDataService
{
    private readonly IndexedDbService _db;

    public InspectionDataService(IndexedDbService db)
    {
        _db = db;
    }

    // Sites
    public async Task<List<Site>> GetSitesAsync() => await _db.GetAllItemsAsync<Site>("sites");

    public async Task<Site?> GetSiteAsync(string id) => await _db.GetItemAsync<Site>("sites", id);

    public async Task SaveSiteAsync(Site site)
    {
        await _db.PutItemAsync("sites", site);
        await AddToSyncQueueAsync("Site", site.Id, SyncOperation.Create, site);
    }

    // Inspections
    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
        => await _db.GetItemsByIndexAsync<Inspection>("inspections", "siteId", siteId);

    public async Task<Inspection?> GetInspectionAsync(string id)
        => await _db.GetItemAsync<Inspection>("inspections", id);

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        await _db.PutItemAsync("inspections", inspection);
        await AddToSyncQueueAsync("Inspection", inspection.Id, SyncOperation.Create, inspection);
    }

    // Checklist Items
    public async Task<List<ChecklistItem>> GetChecklistItemsAsync(string inspectionId)
        => await _db.GetItemsByIndexAsync<ChecklistItem>("checklistItems", "inspectionId", inspectionId);

    public async Task SaveChecklistItemAsync(ChecklistItem item)
    {
        await _db.PutItemAsync("checklistItems", item);
        await AddToSyncQueueAsync("ChecklistItem", item.Id, SyncOperation.Update, item);
    }

    public async Task SaveChecklistItemsAsync(List<ChecklistItem> items)
    {
        foreach (var item in items)
        {
            await _db.PutItemAsync("checklistItems", item);
            await AddToSyncQueueAsync("ChecklistItem", item.Id, SyncOperation.Create, item);
        }
    }

    // Photos
    public async Task<List<Photo>> GetPhotosForInspectionAsync(string inspectionId)
        => await _db.GetItemsByIndexAsync<Photo>("photos", "inspectionId", inspectionId);

    public async Task SavePhotoAsync(Photo photo)
    {
        await _db.PutItemAsync("photos", photo);
        await AddToSyncQueueAsync("Photo", photo.Id, SyncOperation.Create, photo);
    }

    public async Task DeletePhotoAsync(string id)
    {
        await _db.DeleteItemAsync("photos", id);
        await AddToSyncQueueAsync("Photo", id, SyncOperation.Delete, new { Id = id });
    }

    // Sync Queue
    private async Task AddToSyncQueueAsync(string entityType, string entityId, SyncOperation operation, object payload)
    {
        var syncItem = new SyncQueueItem
        {
            EntityType = entityType,
            EntityId = entityId,
            Operation = operation,
            Payload = JsonSerializer.Serialize(payload, new JsonSerializerOptions { PropertyNamingPolicy = JsonNamingPolicy.CamelCase }),
            IsSynced = false
        };
        await _db.PutItemAsync("syncQueue", syncItem);
    }

    // Default checklist
    public List<ChecklistItem> CreateDefaultChecklist(string inspectionId)
    {
        var items = new List<ChecklistItem>();
        var categories = new Dictionary<string, string[]>
        {
            ["Structural Safety"] = new[] { "Foundation integrity", "Load-bearing walls", "Scaffolding secure", "Temporary supports" },
            ["Electrical Safety"] = new[] { "Wiring properly insulated", "GFCI protection", "Panel access clear", "Lockout/tagout compliance" },
            ["Fire Safety"] = new[] { "Extinguishers accessible", "Exit routes clear", "Flammable materials stored properly", "Hot work permits posted" },
            ["General Safety"] = new[] { "PPE worn by workers", "First aid kit stocked", "Safety signage posted", "Housekeeping adequate" },
            ["Site Conditions"] = new[] { "Excavation shoring", "Fall protection in place", "Equipment inspected", "Traffic control adequate" }
        };

        foreach (var (category, descriptions) in categories)
        {
            foreach (var desc in descriptions)
            {
                items.Add(new ChecklistItem
                {
                    InspectionId = inspectionId,
                    Category = category,
                    Description = desc
                });
            }
        }
        return items;
    }
}

using SiteInspector.Client.Models;
using System.Net.Http.Json;

namespace SiteInspector.Client.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly HttpClient _httpClient;
    private Timer? _timer;

    public bool IsOnline { get; private set; }
    public int PendingCount { get; private set; }
    public DateTime? LastSyncTime { get; private set; }
    public event Action? OnStatusChanged;

    public SyncService(IndexedDbService db, HttpClient httpClient)
    {
        _db = db;
        _httpClient = httpClient;
    }

    public async Task StartAsync()
    {
        await CheckConnectivity();
        _timer = new Timer(async _ => await SyncLoop(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    private async Task SyncLoop()
    {
        try
        {
            await CheckConnectivity();
            if (IsOnline)
            {
                await ProcessSyncQueueAsync();
            }
        }
        catch
        {
            // Silently handle sync errors
        }
    }

    public async Task CheckConnectivity()
    {
        try
        {
