public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly HttpClient _httpClient;
    private Timer? _timer;

    public bool IsOnline { get; private set; }
    public int PendingCount { get; private set; }
    public DateTime? LastSyncTime { get; private set; }
    public event Action? OnStatusChanged;

    public SyncService(IndexedDbService db, HttpClient httpClient)
    {
        _db = db;
        _httpClient = httpClient;
    }

    public async Task StartAsync()
    {
        await CheckConnectivity();
        _timer = new Timer(async _ => await SyncLoop(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    private async Task SyncLoop()
    {
        try
        {
            await CheckConnectivity();
            if (IsOnline)
            {
                await ProcessSyncQueueAsync();
            }
        }
        catch
        {
            // Silently handle sync errors
        }
    }

    public async Task CheckConnectivity()
    {
        try
        {
            IsOnline = await _db.IsOnlineAsync();
        }
        catch
        {
            IsOnline = false;
        }
        await UpdatePendingCount();
        OnStatusChanged?.Invoke();
    }

    private async Task UpdatePendingCount()
    {
        try
        {
            var items = await _db.GetPendingSyncItemsAsync<SyncQueueItem>();
            PendingCount = items.Count;
        }
        catch
        {
            PendingCount = 0;
        }
    }

    public async Task ProcessSyncQueueAsync()
    {
        var pendingItems = await _db.GetPendingSyncItemsAsync<SyncQueueItem>();
        if (pendingItems.Count == 0) return;

        try
        {
            var response = await _httpClient.PostAsJsonAsync("/api/sync", pendingItems);
            if (response.IsSuccessStatusCode)
            {
                foreach (var item in pendingItems)
                {
                    await _db.MarkAsSyncedAsync(item.Id);
                }
                LastSyncTime = DateTime.UtcNow;
            }
        }
        catch
        {
            // Will retry on next cycle
        }

        await UpdatePendingCount();
        OnStatusChanged?.Invoke();
    }

    public void Dispose()
    {
        _timer?.Dispose();
    }
}

