@page "/"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject InspectionDataService DataService
@inject NavigationManager Navigation

<PageTitle>Site Inspector</PageTitle>

<div class="page-container">
    <div class="page-header">
        <h1>Construction Sites</h1>
        <button class="btn btn-primary btn-lg" @onclick="ShowAddSite">+ Add Site</button>
    </div>

    @if (_showAddForm)
    {
        <div class="card add-form-card">
            <div class="card-body">
                <h5>New Site</h5>
                <div class="mb-3">
                    <input type="text" class="form-control form-control-lg" placeholder="Site Name" @bind="_newSiteName" />
                </div>
                <div class="mb-3">
                    <input type="text" class="form-control form-control-lg" placeholder="Address" @bind="_newSiteAddress" />
                </div>
                <div class="d-flex gap-2">
                    <button class="btn btn-success btn-lg flex-fill" @onclick="AddSite">Save</button>
                    <button class="btn btn-secondary btn-lg flex-fill" @onclick="CancelAdd">Cancel</button>
                </div>
            </div>
        </div>
    }

    @if (_sites == null)
    {
        <div class="loading">Loading sites...</div>
    }
    else if (_sites.Count == 0)
    {
        <div class="empty-state">
            <p>No sites yet. Add your first construction site to get started.</p>
        </div>
    }
    else
    {
        <div class="site-list">
            @foreach (var site in _sites.OrderByDescending(s => s.CreatedDate))
            {
                <div class="site-card" @onclick="() => NavigateToSite(site.Id)">
                    <div class="site-card-content">
                        <h3>@site.Name</h3>
                        <p class="site-address">@site.Address</p>
                        <small class="text-muted">Created @site.CreatedDate.ToString("MMM dd, yyyy")</small>
                    </div>
                    <div class="site-card-arrow">›</div>
                </div>
            }
        </div>
    }
</div>

@code {
    private List<Site>? _sites;
    private bool _showAddForm;
    private string _newSiteName = string.Empty;
    private string _newSiteAddress = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _sites = await DataService.GetSitesAsync();
    }

    private void ShowAddSite() => _showAddForm = true;
    private void CancelAdd() { _showAddForm = false; _newSiteName = string.Empty; _newSiteAddress = string.Empty; }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;
        var site = new Site { Name = _newSiteName, Address = _newSiteAddress };
        await DataService.SaveSiteAsync(site);
        _sites = await DataService.GetSitesAsync();
        _showAddForm = false;
        _newSiteName = string.Empty;
        _newSiteAddress = string.Empty;
    }

    private void NavigateToSite(string id) => Navigation.NavigateTo($"/site/{id}");
}

