@page "/site/{SiteId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject InspectionDataService DataService
@inject NavigationManager Navigation

<PageTitle>Site Details</PageTitle>

<div class="page-container">
    @if (_site == null)
    {
        <div class="loading">Loading...</div>
    }
    else
    {
        <div class="page-header">
            <button class="btn btn-outline-secondary" @onclick="GoBack">← Back</button>
            <h1>@_site.Name</h1>
        </div>
        <div class="site-info card">
            <div class="card-body">
                <p><strong>Address:</strong> @_site.Address</p>
                @if (!string.IsNullOrEmpty(_site.Notes))
                {
                    <p><strong>Notes:</strong> @_site.Notes</p>
                }
            </div>
        </div>

        <div class="section-header">
            <h2>Inspections</h2>
            <button class="btn btn-primary btn-lg" @onclick="NewInspection">+ New Inspection</button>
        </div>

        @if (_inspections == null || _inspections.Count == 0)
        {
            <div class="empty-state">
                <p>No inspections yet. Start a new inspection to begin.</p>
            </div>
        }
        else
        {
            <div class="inspection-list">
                @foreach (var inspection in _inspections.OrderByDescending(i => i.Date))
                {
                    <div class="inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                        <div class="inspection-status @(inspection.Status == InspectionStatus.Complete ? "status-complete" : "status-progress")">
                            @(inspection.Status == InspectionStatus.Complete ? "✓" : "⋯")
                        </div>
                        <div class="inspection-card-content">
                            <h4>@inspection.Date.ToString("MMM dd, yyyy HH:mm")</h4>
                            <p>Inspector: @inspection.InspectorName</p>
                            <span class="badge @(inspection.Status == InspectionStatus.Complete ? "bg-success" : "bg-warning")">
                                @inspection.Status
                            </span>
                        </div>
                        <div class="site-card-arrow">›</div>
                    </div>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private Site? _site;
    private List<Inspection>? _inspections;

    protected override async Task OnInitializedAsync()
    {
        _site = await DataService.GetSiteAsync(SiteId);
        _inspections = await DataService.GetInspectionsForSiteAsync(SiteId);
    }

    private void GoBack() => Navigation.NavigateTo("/");
    private void NewInspection() => Navigation.NavigateTo($"/site/{SiteId}/new-inspection");
    private void OpenInspection(string id) => Navigation.NavigateTo($"/inspection/{id}");
}

