<PageTitle>New Inspection</PageTitle>

<div class="page-container">
    <div class="page-header">
        <button class="btn btn-outline-secondary" @onclick="GoBack">← Back</button>
        <h1>New Inspection</h1>
    </div>

    <div class="card">
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Inspector Name</label>
                <input type="text" class="form-control form-control-lg" @bind="_inspectorName" placeholder="Your name" />
            </div>
            <div class="mb-3">
                <label class="form-label">Notes</label>
                <textarea class="form-control" rows="3" @bind="_notes" placeholder="Initial observations..."></textarea>
            </div>
            <button class="btn btn-success btn-lg w-100" @onclick="CreateInspection" disabled="@_creating">
                @(_creating ? "Creating..." : "Start Inspection")
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private string _inspectorName = string.Empty;
    private string _notes = string.Empty;
    private bool _creating;

    private async Task CreateInspection()
    {
        if (string.IsNullOrWhiteSpace(_inspectorName)) return;
        _creating = true;

        var inspection = new Inspection
        {
            SiteId = SiteId,
            InspectorName = _inspectorName,
            Notes = _notes,
            Status = InspectionStatus.InProgress
        };

        await DataService.SaveInspectionAsync(inspection);

        var checklistItems = DataService.CreateDefaultChecklist(inspection.Id);
        await DataService.SaveChecklistItemsAsync(checklistItems);

        Navigation.NavigateTo($"/inspection/{inspection.Id}");
    }

    private void GoBack() => Navigation.NavigateTo($"/site/{SiteId}");
}

