+            if (_checklistByCategory.Any())
+                _expandedCategories.Add(_checklistByCategory.Keys.First());
+        }
+    }
+
+    private void ToggleCategory(string category)
+    {
+        if (!_expandedCategories.Add(category))
+            _expandedCategories.Remove(category);
+    }
+
+    private async Task ToggleItem(ChecklistItem item)
+    {
+        item.IsChecked = !item.IsChecked;
+        item.CheckedDate = item.IsChecked ? DateTime.UtcNow : null;
+        await DataService.SaveChecklistItemAsync(item);
+    }
+
+    private void ShowItemNotes(ChecklistItem item)
+    {
+        _editingItem = item;
+        _editingItemNotes = item.Notes;
+    }
+
+    private async Task SaveItemNotes()
+    {
+        if (_editingItem != null)
+        {
+            _editingItem.Notes = _editingItemNotes;
+            await DataService.SaveChecklistItemAsync(_editingItem);
+        }
+        _editingItem = null;
+    }
+
+    private void CloseItemNotes() => _editingItem = null;
+
+    private async Task HandlePhotoUpload(InputFileChangeEventArgs e)
+    {
+        var file = e.File;
+        if (file == null) return;
+
+        using var stream = file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024);
+        using var ms = new MemoryStream();
+        await stream.CopyToAsync(ms);
+        var base64 = Convert.ToBase64String(ms.ToArray());
+
+        var photo = new Photo
+        {
+            InspectionId = InspectionId,
+            FileName = file.Name,
+            Base64Data = base64,
+            Caption = string.Empty
+        };
+
+        await DataService.SavePhotoAsync(photo);
+        _photos.Add(photo);
+    }
+
+    private async Task DeletePhoto(Photo photo)
+    {
+        await DataService.DeletePhotoAsync(photo.Id);
+        _photos.Remove(photo);
+    }
+
+    private async Task SaveNotes()
+    {
+        if (_inspection != null)
+            await DataService.SaveInspectionAsync(_inspection);
+    }
+
+    private async Task CompleteInspection()
+    {
+        if (_inspection != null)
+        {
+            _inspection.Status = InspectionStatus.Complete;
+            await DataService.SaveInspectionAsync(_inspection);
+        }
+    }
+
+    private void GoBack()
+    {
+        if (_inspection != null)
+            Navigation.NavigateTo($"/site/{_inspection.SiteId}");
+        else
+            Navigation.NavigateTo("/");
+    }
+}
