using System.Text.Json;

namespace SiteInspector.Endpoints;

public static class SyncEndpoints
{
    private static readonly List<JsonElement> _syncedData = new();
    private static readonly Dictionary<string, JsonElement> _sites = new();
    private static readonly Dictionary<string, JsonElement> _inspections = new();

    public static void MapSyncEndpoints(this WebApplication app)
    {
        app.MapPost("/api/sync", (JsonElement[] items) =>
        {
            foreach (var item in items)
            {
                _syncedData.Add(item);

                if (item.TryGetProperty("entityType", out var entityType) &&
                    item.TryGetProperty("entityId", out var entityId) &&
                    item.TryGetProperty("payload", out var payload))
                {
                    var type = entityType.GetString();
                    var id = entityId.GetString();
                    if (type == "Site" && id != null)
                    {
                        _sites[id] = payload;
                    }
                    else if (type == "Inspection" && id != null)
                    {
                        _inspections[id] = payload;
                    }
                }
            }
            return Results.Ok(new { processed = items.Length });
        });

        app.MapGet("/api/sites", () =>
        {
            return Results.Ok(_sites.Values);
        });

        app.MapGet("/api/inspections/{siteId}", (string siteId) =>
        {
            var results = _inspections.Values.Where(i =>
            {
                if (i.TryGetProperty("siteId", out var sid))
                    return sid.GetString() == siteId;
                return false;
            });
            return Results.Ok(results);
        });
    }
}

{
  "name": "Site Inspector",
  "short_name": "Inspector",
  "description": "Construction site inspection app for building inspectors",
  "start_url": "/",
  "display": "standalone",
  "background_color": "#1a1a2e",
  "theme_color": "#0f3460",
  "orientation": "portrait-primary",
  "icons": [
    {
      "src": "icon-192.png",
      "sizes": "192x192",
      "type": "image/png"
    },
    {
      "src": "icon-512.png",
      "sizes": "512x512",
      "type": "image/png"
    }
  ]
}

// In development, always fetch from network
self.addEventListener('install', event => event.waitUntil(self.skipWaiting()));
self.addEventListener('activate', event => event.waitUntil(self.clients.claim()));
self.addEventListener('fetch', () => { });

const CACHE_NAME = 'site-inspector-cache-v1';
const OFFLINE_URLS = [
    '/',
    '/css/app.css',
    '/manifest.webmanifest'
];

self.addEventListener('install', event => {
    event.waitUntil(
        caches.open(CACHE_NAME).then(cache => cache.addAll(OFFLINE_URLS))
    );
    self.skipWaiting();
});

self.addEventListener('activate', event => {
    event.waitUntil(
        caches.keys().then(keys =>
            Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
        )
    );
    self.clients.claim();
});

self.addEventListener('fetch', event => {
    if (event.request.method !== 'GET') return;

    const url = new URL(event.request.url);

    // For API calls, try network first
    if (url.pathname.startsWith('/api/')) {
        event.respondWith(
            fetch(event.request).catch(() => caches.match(event.request))
        );
        return;
    }

    // For everything else, cache first
    event.respondWith(
        caches.match(event.request).then(cached => {
            if (cached) return cached;
            return fetch(event.request).then(response => {
                if (response.ok) {
                    const clone = response.clone();
                    caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
                }
                return response;
            });
        }).catch(() => caches.match('/'))
    );
});

